#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 5000
#define MAX_STRENGTH 1000000000
int max(int a, int b) { return a > b ? a : b; }
int sum_of_digits(int n) { int sum = 0; while (n > 0) { sum += n % 10; n /= 10; } return sum; }
int cube(int n) { return n * n * n; }
int dp[MAX + 1][MAX_STRENGTH + 1];
int main() {
    int N, Sin;
    scanf("%d %d", &N, &Sin);
    int E[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &E[i]);
    }
    for (int i = 0; i <= N; i++) {
        for (int j = 0; j <= MAX_STRENGTH; j++) {
            dp[i][j] = 0;
        }
    }
    for (int i = 1; i <= N; i++) {
        for (int j = 0; j <= MAX_STRENGTH; j++) {
            if (i == 1) {
                dp[i][j] = max(dp[i][j], dp[i - 1][j] + j * E[i - 1]);
                int new_strength = j + cube(sum_of_digits(j));
                if (new_strength <= MAX_STRENGTH) {
                    dp[i][new_strength] = max(dp[i][new_strength], dp[i - 1][j]);
                }
            } else {
                dp[i][j] = max(dp[i][j], dp[i - 1][j] + j * E[i - 1]);
                int new_strength = j + cube(sum_of_digits(j));
                if (new_strength <= MAX_STRENGTH) {
                    dp[i][new_strength] = max(dp[i][new_strength], dp[i - 1][j]);
                }
            }
        }
    }
    int max_XV = 0;
    for (int j = 0; j <= MAX_STRENGTH; j++) {
        max_XV = max(max_XV, dp[N][j]);
    }
    printf("%d\n", max_XV);
    return 0;
}

